import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: 'POND_PROCESS', label: 'Xử lý ao (POND_PROCESS)' },
  { value: 'FEEDING', label: 'Cho ăn (FEEDING)' },
  { value: 'TREATMENT', label: 'Cho thuốc (TREATMENT)' },
  { value: 'ENVIRONMENTAL_CHECK', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: 'HARVEST', label: 'Thu hoạch (HARVEST)' },
  { value: 'OTHER', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA STATE =====
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  // ===== UI STATE =====
  const [loading, setLoading] = useState(true)
  const [loadingPonds, setLoadingPonds] = useState(false)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [currentPage, setCurrentPage] = useState(1)
  const [pageSize, setPageSize] = useState(10)
  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)

  // ===== FORM STATE (HỖ TRỢ MA TRẬN) =====
  const initialForm = {
  task_type: '',
  assignments: [], // Sử dụng mảng này thay vì selected_ponds và assigned_workers
  task_title: '',
  description: '',
  start_date: '',
  due_date: '',
  product_id: '',
  quantity: '',
}
  const [form, setForm] = useState(initialForm)

  // ==========================================
  // LOGIC TỰ ĐỘNG ĐÁNH GIÁ QUÁ HẠN (REALTIME)
  // ==========================================
  const getComputedStatus = (task) => {
    const baseStatus = normalize(task.status)
    if (['COMPLETED', 'CANCELLED'].includes(baseStatus)) {
      return baseStatus
    }
    if (task.due_date && new Date(task.due_date) < new Date()) {
      return 'OVERDUE'
    }
    return baseStatus
  }

  const getStatusLabel = (task) => {
    const computed = getComputedStatus(task)
    switch (computed) {
      case 'PENDING': return 'Chờ xử lý'
      case 'IN_PROGRESS': return 'Đang thực hiện'
      case 'COMPLETED': return 'Hoàn thành'
      case 'CANCELLED': return 'Đã hủy'
      case 'OVERDUE': return 'Quá hạn (Hệ thống)'
      default: return task.status || '-'
    }
  }

  const getStatusBadgeClass = (task) => {
    const computed = getComputedStatus(task)
    switch (computed) {
      case 'PENDING': return 'task-status task-status--pending'
      case 'IN_PROGRESS': return 'task-status task-status--progress'
      case 'COMPLETED': return 'task-status task-status--done'
      case 'CANCELLED': return 'task-status bg-gray-400'
      case 'OVERDUE': return 'task-status bg-red-500 font-bold'
      default: return 'task-status bg-slate-500'
    }
  }

  // =========================
  // FETCH DATA FROM API
  // =========================
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách công việc', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh mục sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkersStatus = useCallback(async () => {
    try {
      const res = await taskService.getWorkersStatus()
      setWorkers(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được trạng thái nhân công', type: 'error' })
    }
  }, [])

  useEffect(() => {
    const loadInitialData = async () => {
      setLoading(true)
      await Promise.all([
        fetchTasks(),
        fetchProducts(),
        fetchWorkersStatus()
      ])
      setLoading(false)
    }
    loadInitialData()
  }, [fetchTasks, fetchProducts, fetchWorkersStatus])

  const handleTypeChange = async (e) => {
    const typeCode = e.target.value ? e.target.value.trim().toUpperCase() : ''

    setForm(prev => ({
      ...prev,
      task_type: typeCode,
      selected_ponds: [],
      product_id: '',
      quantity: ''
    }))
    setPonds([])

    if (!typeCode) return

    setLoadingPonds(true)
    try {
      const res = await taskService.getPondsByType(typeCode)
      setPonds(res?.data?.data || [])
    } catch (err) {
      console.error("API Error Details:", err.response?.data)
      showToast({ title: 'Lỗi khi tự động lọc danh sách ao tương ứng', type: 'error' })
    } finally {
      setLoadingPonds(false)
    }
  }

  const togglePondSelection = (pondId) => {
    const targetId = Number(pondId)
    if (!targetId) return
    setForm(prev => {
      const current = prev.selected_ponds || []
      const exists = current.includes(targetId)
      return {
        ...prev,
        selected_ponds: exists ? current.filter(id => id !== targetId) : [...current, targetId]
      }
    })
  }

  const toggleWorkerSelection = (workerId, isBusy) => {
    // Quy tắc 2.3: Ngăn không cho tick nếu công nhân bận
    if (isBusy) return;

    setForm(prev => {
      const current = prev.assigned_workers || [];
      const exists = current.includes(workerId);
      return {
        ...prev,
        assigned_workers: exists ? current.filter(id => id !== workerId) : [...current, workerId]
      };
    });
  };

  const toggleAllPonds = () => {
    setForm(prev => {
      if (prev.selected_ponds.length === ponds.length) {
        return { ...prev, selected_ponds: [] }
      } else {
        return { ...prev, selected_ponds: ponds.map(p => Number(p.pond_id)) }
      }
    })
  }

  const toggleAllWorkers = () => {
    setForm(prev => {
      const availableWorkers = workers.filter(w => normalize(w.work_status) !== 'BUSY').map(w => Number(w.worker_id || w.user_id || w.id))
      if (prev.assigned_workers.length === availableWorkers.length) {
        return { ...prev, assigned_workers: [] }
      } else {
        return { ...prev, assigned_workers: availableWorkers }
      }
    })
  }

  const toggleAssignment = (workerId, pondId) => {
    setForm(prev => {
      const exists = prev.assignments.some(a => a.worker_id === workerId && a.pond_id === pondId);

      return {
        ...prev,
        assignments: exists
          ? prev.assignments.filter(a => !(a.worker_id === workerId && a.pond_id === pondId))
          : [...prev.assignments, { worker_id: workerId, pond_id: pondId }]
      };
    });
  };

  // =========================
  // FILTER & PAGINATION LOGIC
  // =========================
  const filteredTasks = useMemo(() => {
    const s = search.trim().toLowerCase()
    return tasks.filter((t) => {
      const matchSearch = !s ||
        String(t.task_title || '').toLowerCase().includes(s) ||
        String(t.pond_name || '').toLowerCase().includes(s)

      const computedStatus = getComputedStatus(t)
      const matchStatus = statusFilter === 'ALL' || computedStatus === statusFilter
      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize))
  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages)
    }
  }, [filteredTasks.length, pageSize, totalPages, currentPage])

  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filteredTasks.length)
  const paginatedTasks = filteredTasks.slice(startIndex, endIndex)

  const isProductRequired = useMemo(() => {
    return ['FEEDING', 'TREATMENT', 'POND_PROCESS'].includes(form.task_type)
  }, [form.task_type])

  // ==========================================
  // XỬ LÝ SUBMIT - TẠO MỚI CÔNG VIỆC MA TRẬN
  // ==========================================
  const handleCreateTask = async () => {
  // 1. Kiểm tra điều kiện (Sử dụng form.assignments)
  if (!form.assignments || form.assignments.length === 0) {
    showToast({ title: 'Vui lòng chọn ít nhất một phân công trong ma trận', type: 'warning' })
    return
  }
  if (!form.description?.trim()) {
    showToast({ title: 'Vui lòng nhập hướng dẫn chi tiết công việc', type: 'warning' })
    return
  }

  // Đếm số lượng công việc sẽ tạo (mỗi cặp assignment là 1 task)
  const confirmAction = window.confirm(`Xác nhận tạo ${form.assignments.length} công việc cho các cặp nhân công-ao đã chọn?`)
  if (!confirmAction) return

  setLoading(true)

  try {
    let finalTitle = form.task_title?.trim()
    if (!finalTitle) {
      const typeOpt = TASK_TYPE_OPTIONS.find(o => o.value === form.task_type)
      finalTitle = typeOpt ? `Công tác ${typeOpt.label}` : 'Công việc kỹ thuật ao'
    }

    const TASK_TYPE_MAP_ID = {
      'POND_PROCESS': 1, 'FEEDING': 2, 'TREATMENT': 3, 
      'ENVIRONMENTAL_CHECK': 4, 'HARVEST': 5, 'OTHER': 6
    }
    const currentNumericTypeId = TASK_TYPE_MAP_ID[form.task_type] || 6

    // 2. Duyệt qua mảng assignments thay vì danh sách ao
    for (const assignment of form.assignments) {
      const { worker_id, pond_id } = assignment
      const selectedPondObj = ponds.find(p => Number(p.pond_id) === Number(pond_id))

      const singleTaskData = {
        type_id: Number(currentNumericTypeId),
        task_type: form.task_type,
        pond_id: Number(pond_id),
        task_title: finalTitle,
        description: form.description,
        start_date: form.start_date,
        due_date: form.due_date,
        // Chỉ gửi đúng 1 công nhân duy nhất được gán cho task này
        assigned_workers: [Number(worker_id)] 
      }

      if (selectedPondObj && selectedPondObj.season_id) {
        singleTaskData.season_id = Number(selectedPondObj.season_id)
      }

      if (isProductRequired && form.product_id) {
        singleTaskData.product_id = Number(form.product_id)
        singleTaskData.quantity = parseFloat(form.quantity) || 0
      }

      // Gọi API cho từng cặp phân công
      await taskService.createTask(singleTaskData)
    }

    showToast({ title: `Đã phân công thành công ${form.assignments.length} công việc!`, type: 'success' })
    setForm(initialForm)
    setIsCreateOpen(false)
    await Promise.all([fetchTasks(), fetchWorkersStatus()])
  } catch (err) {
    console.error("Lỗi:", err.response?.data)
    showToast({ title: err.response?.data?.message || 'Có lỗi xảy ra khi tạo công việc', type: 'error' })
  } finally {
    setLoading(false)
  }
}

  // ==========================================
  // TECHNICIAN CHỈ CÓ QUYỀN HỦY BỎ TÁC VỤ
  // ==========================================
  const handleCancelTask = async (taskId) => {
    const confirmCancel = window.confirm("Bạn có chắc chắn muốn HỦY bỏ hoàn toàn công việc này không?")
    if (!confirmCancel) return

    try {
      await taskService.cancelTask(taskId)
      showToast({ title: 'Đã hủy công việc thành công', type: 'success' })
      setSelectedTask(null)
      await Promise.all([fetchTasks(), fetchWorkersStatus()])
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Không thể hủy công việc', type: 'error' })
    }
  }

  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  // Hàm tìm tên nhân viên từ danh sách workers dựa trên danh sách ID (assigned_workers)
  const getAssignedWorkersName = (task) => {
    // Dữ liệu mới từ Backend (dạng mảng object)
    if (task.assigned_workers_list && Array.isArray(task.assigned_workers_list)) {
      return task.assigned_workers_list.map(w => w.full_name).join(', ');
    }

    // Fallback nếu chưa kịp update backend
    return 'Chưa phân công';
  };

  return (
    <div className="dashboard admin-page technician-tasks">
      <div className="table-container table-panel">

        {/* MAIN TABLE HEADER */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Giám sát và phân phối ma trận việc làm cho Công nhân kỹ thuật</p>
          </div>
          <button type="button" className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
            + Phân công việc (Hệ Ma trận)
          </button>
        </div>

        {/* TOOLBAR & FILTER */}
        <div className="technician-tasks_toolbar">
          <input
            type="text"
            placeholder="Tìm theo tên công việc hoặc ao..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            {STATUS_OPTIONS.map((o, idx) => (
              <option key={`status-filter-${o.value}-${idx}`} value={o.value}>{o.label}</option>
            ))}
          </select>
        </div>

        {/* DATA TABLE */}
        <div className="table-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Công việc</th>
                <th>Ao nuôi</th>
                <th>Phụ trách thực hiện</th>
                <th>Hạn hoàn thành</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {paginatedTasks.length === 0 ? (
                <tr>
                  <td className="table-empty-row" colSpan="6">Không có dữ liệu...</td>
                </tr>
              ) : (
                paginatedTasks.map((t, idx) => (
                  <tr key={`task-row-${t.task_id || idx}`}>
                    <td>
                      <div className="technician-ponds_name-block">
                        <strong>{t.task_title}</strong>
                      </div>
                    </td>
                    <td>{t.pond_name || '-'}</td>
                    <td>
                      <div className="worker-info-cell">
                        <strong>{getAssignedWorkersName(t)}</strong>
                      </div>
                    </td>
                    <td>{formatDate(t.due_date)}</td>
                    <td>
                      <span className={getStatusBadgeClass(t)}>
                        {getStatusLabel(t)}
                      </span>
                    </td>
                    <td>
                      <button type="button" className="table-action-btn" onClick={() => setSelectedTask(t)}>
                        ⓘ
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* PAGINATION */}
        <div className="table-pagination">
          <div className="table-pagination-left">
            <span>Số mục trên trang</span>
            <select
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value) || 10)
                setCurrentPage(1)
              }}
            >
              {[5, 10, 20, 50].map((size, idx) => (
                <option key={`page-size-opt-${size}-${idx}`} value={size}>{size}</option>
              ))}
            </select>
            <span>{filteredTasks.length === 0 ? 0 : startIndex + 1}-{endIndex} / {filteredTasks.length}</span>
          </div>

          <div className="table-pagination-right">
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage <= 1}
              onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            >
              ‹
            </button>
            <span className="table-page-pill">{safePage}</span>
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage >= totalPages}
              onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content admin-users_modal admin-users_modal--detail" onClick={(e) => e.stopPropagation()}>
            <h3>Chi tiết tiến độ công việc</h3>

            <div className="admin-users_detail-grid">
              {/* Các trường thông tin mới bổ sung */}
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Mã công việc</span>
                <strong>{selectedTask.task_code || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Loại công việc</span>
                <strong>{selectedTask.type_name || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Tiêu đề công việc</span>
                <strong>{selectedTask.task_title || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Ao nuôi</span>
                <strong>{selectedTask.pond_name || '-'} (Mã: {selectedTask.pond_code || '-'})</strong>
              </div>

              {/* Thời gian */}
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Bắt đầu</span>
                <strong>{formatDate(selectedTask.start_date)}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Hạn chót</span>
                <strong>{formatDate(selectedTask.due_date)}</strong>
              </div>

              {/* Thời gian thực tế (Nếu đã hoàn thành) */}
              {selectedTask.completed_at && (
                <div className="admin-users_detail-card">
                  <span className="admin-users_detail-label">Hoàn thành thực tế</span>
                  <strong style={{ color: 'green' }}>{formatDate(selectedTask.completed_at)}</strong>
                </div>
              )}

              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Nhân công phụ trách</span>
                <strong>{getAssignedWorkersName(selectedTask)}</strong>
              </div>

              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Trạng thái</span>
                <div className="inline-badge-mt">
                  <span className={getStatusBadgeClass(selectedTask)}>
                    {getStatusLabel(selectedTask)}
                  </span>
                </div>
              </div>

              {/* Vật tư */}
              {selectedTask.product_info && (
                <div className="admin-users_detail-card detail-card--product">
                  <span className="admin-users_detail-label label--product">Vật tư chỉ định</span>
                  <strong>{selectedTask.product_info.product_name} — SL: {selectedTask.product_info.quantity} {selectedTask.product_info.unit || ''}</strong>
                </div>
              )}

              {/* Mô tả */}
              <div className="admin-users_detail-card detail-card--fullwidth">
                <span className="admin-users_detail-label">Hướng dẫn kỹ thuật</span>
                <p className="technical-instruction-text">{selectedTask.description || 'Không có hướng dẫn chi tiết.'}</p>
              </div>
            </div>

            {/* Hình ảnh báo cáo */}
            {selectedTask.task_images && selectedTask.task_images.length > 0 && (
              <div style={{ marginTop: '16px' }}>
                <span className="admin-users_detail-label">Hình ảnh báo cáo thực địa:</span>
                <div className="task-images">
                  {selectedTask.task_images.map((imgUrl, i) => (
                    <img key={`task-img-${i}`} src={imgUrl} alt={`Ảnh ${i + 1}`} onClick={() => window.open(imgUrl, '_blank')} />
                  ))}
                </div>
              </div>
            )}

            {/* Nút hành động */}
            <div className="admin-users_modal-buttons admin-users_form-buttons modal-actions-space-between">
              <div>
                {normalize(selectedTask.status) === 'PENDING' && (
                  <button type="button" className="btn btn-danger" onClick={() => handleCancelTask(selectedTask.task_id)}>
                    Hủy công việc
                  </button>
                )}
              </div>
              <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng lại</button>
            </div>
          </div>
        </div>
      )}

      {/* CREATE TASK MODAL (BẢN MA TRẬN PHÂN VIỆC) */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content admin-users_modal modal-matrix-width" onClick={(e) => e.stopPropagation()}>
            <div className="matrix-modal-header">
              <h3>Phân công công việc Hệ Ma Trận</h3>
              <p>Hệ thống tự động đồng bộ một nội dung hướng dẫn cho nhiều ao nuôi và nhóm nhân công được tích chọn.</p>
            </div>

            <div className="form-column-gap-16">

              {/* LOẠI CÔNG VIỆC */}
              <div>
                <label className="admin-users_detail-label">Loại công việc kỹ thuật <span className="text-red">*</span></label>
                <select
                  className="table-filter select-fullwidth-mt"
                  value={form.task_type}
                  onChange={handleTypeChange}
                >
                  <option value="">-- Chọn loại công việc để kích hoạt ma trận --</option>
                  {TASK_TYPE_OPTIONS.map((opt, idx) => (
                    <option key={`create-type-opt-${opt.value}-${idx}`} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>

              {/* KHU VỰC HIỂN THỊ MA TRẬN PHÂN VIỆC */}
              {form.task_type && (
                <div className="matrix-container">
                  <div className="matrix-header-bar">
                    <strong>MA TRẬN PHÂN CÔNG (NHÂN CÔNG × AO NUÔI)</strong>
                  </div>

                  <div className="matrix-scroll-wrapper">
                    <table className="matrix-table-base">
                      <thead>
                        <tr>
                          <th className="matrix-th-worker" style={{ textAlign: 'left' }}>Nhân công / Ao nuôi</th>
                          {ponds.map(p => (
                            <th key={`head-pond-${p.pond_id}`} className="matrix-th-pond" style={{ textAlign: 'center' }}>
                              {p.pond_name}
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {workers.map((w, wIdx) => {
                          const wId = Number(w.worker_id || w.user_id || w.id);
                          const isBusy = normalize(w.work_status) === 'BUSY';

                          return (
                            <tr key={`row-worker-${wId}`}>
                              <td className="matrix-td-worker" style={{ padding: '10px' }}>
                                <div className="worker-info">
                                  <strong>{w.full_name || w.username}</strong>
                                  <div style={{ fontSize: '11px', color: isBusy ? 'red' : 'green' }}>
                                    {isBusy ? 'Đang bận' : 'Đang hoạt động'}
                                  </div>
                                </div>
                              </td>

                              {ponds.map(p => {
                                const pId = Number(p.pond_id);
                                const isChecked = form.assignments.some(a => a.worker_id === wId && a.pond_id === pId);

                                return (
                                  <td key={`cell-${wId}-${pId}`} style={{ textAlign: 'center' }}>
                                    <input
                                      type="checkbox"
                                      checked={isChecked}
                                      disabled={isBusy && !isChecked}
                                      onChange={() => toggleAssignment(wId, pId)}
                                    />
                                  </td>
                                );
                              })}
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}

              {/* TIÊU ĐỀ */}
              <div>
                <label className="admin-users_detail-label">Tiêu đề công việc mẫu (Để trống sẽ tự sinh theo loại việc)</label>
                <input
                  type="text"
                  placeholder="Ví dụ: Kiểm tra định kỳ thông số môi trường nước..."
                  className="form-input-text-base"
                  value={form.task_title}
                  onChange={(e) => setForm({ ...form, task_title: e.target.value })}
                />
              </div>

              {/* MÔ TẢ HƯỚNG DẪN */}
              <div>
                <label className="admin-users_detail-label">Hướng dẫn kỹ thuật chi tiết chung <span className="text-red">*</span></label>
                <textarea
                  placeholder="Nội dung này sẽ được copy đồng loạt sang tất cả các ao nuôi bạn chọn ở bảng ma trận phía trên..."
                  className="form-textarea-base"
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                />
              </div>

              {/* VẬT TƯ */}
              {isProductRequired && (
                <div className="product-required-box">
                  <div>
                    <label className="admin-users_detail-label text-blue-label">Vật tư chỉ định sử dụng</label>
                    <select
                      className="table-filter select-fullwidth-bg-white"
                      value={form.product_id}
                      onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                    >
                      <option value="">-- Chọn sản phẩm trong kho --</option>
                      {products.map((p, idx) => (
                        <option key={`create-prod-opt-${p.product_id}-${idx}`} value={p.product_id}>
                          {p.product_name}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="admin-users_detail-label text-blue-label">Số lượng định mức (cho mỗi ao)</label>
                    <input
                      type="number"
                      placeholder="Khối lượng dùng riêng cho mỗi ao..."
                      className="form-input-number-bg-white"
                      value={form.quantity}
                      min="0"
                      step="0.01"
                      onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                    />
                  </div>
                </div>
              )}

              {/* LỊCH TRÌNH */}
              <div className="grid-two-columns">
                <div>
                  <label className="admin-users_detail-label">Thời gian bắt đầu <span className="text-red">*</span></label>
                  <input
                    type="datetime-local"
                    className="form-input-date-base"
                    value={form.start_date}
                    onChange={(e) => setForm({ ...form, start_date: e.target.value })}
                  />
                </div>
                <div>
                  <label className="admin-users_detail-label">Hạn chót hoàn thành <span className="text-red">*</span></label>
                  <input
                    type="datetime-local"
                    className="form-input-date-base"
                    value={form.due_date}
                    onChange={(e) => setForm({ ...form, due_date: e.target.value })}
                  />
                </div>
              </div>

            </div>

            {/* BUTTON ACTIONS */}
            <div className="admin-users_modal-buttons admin-users_form-buttons margin-top-24">
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleCreateTask}
                disabled={form.assignments.length === 0 || !form.start_date || !form.due_date}
              >
                Xác nhận phân công ({form.selected_ponds.length} Ao × {form.assigned_workers.length} Người)
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
